@namespace Lumeo

<nav aria-label="breadcrumb" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</nav>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(Class);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<li role="presentation" class="@CssClass" @attributes="AdditionalAttributes">
    <SvgGlyph Svg="@(LumeoIcons.Ellipsis)" class="h-4 w-4" />
    <span class="sr-only">@L["Common.More"]</span>
</li>

@code {
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("flex items-center justify-center", Class);
}

@namespace Lumeo

<li class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</li>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex items-center gap-1.5", Class);
}

@namespace Lumeo

<a href="@Href" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</a>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Href { get; set; } = "#";
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("cursor-pointer transition-colors hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-sm", Class);
}

@namespace Lumeo

<ol class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</ol>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("flex flex-wrap items-center gap-1.5 break-words text-sm text-muted-foreground sm:gap-2.5", Class);
}

@namespace Lumeo

<span role="link" aria-disabled="true" aria-current="page" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</span>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("font-normal text-foreground", Class);
}

@namespace Lumeo

<li role="presentation" aria-hidden="true" class="@CssClass" @attributes="AdditionalAttributes">
    @if (ChildContent is not null)
    {
        @ChildContent
    }
    else
    {
        <SvgGlyph Svg="@(LumeoIcons.ChevronRight)" class="h-3.5 w-3.5 [dir=rtl]:rotate-180" />
    }
</li>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("[&>svg]:h-3.5 [&>svg]:w-3.5", Class);
}
